transform_js:
var h = Math.sqrt(3) / 2;
transformedData = rawData.rows.map(function(r) {
  var total = r.a + r.b + r.c;
  var a = r.a / total;
  var b = r.b / total;
  var c = r.c / total;
  var x = 0.5 * (2 * b + c);
  var y = h * c;
  return { name: r.label, value: [x, y], a: r.a, b: r.b, c: r.c };
});

echarts_js:
var h = Math.sqrt(3) / 2;
option = {
  title: { text: 'Soil Composition (Ternary)', left: 'center' },
  tooltip: { formatter: function(p) { var d = p.data; return d.name + '<br/>A: ' + d.a + '%<br/>B: ' + d.b + '%<br/>C: ' + d.c + '%'; } },
  xAxis: { type: 'value', min: 0, max: 1, show: false },
  yAxis: { type: 'value', min: 0, max: h, show: false },
  series: [
    {
      type: 'custom',
      renderItem: function(params, api) {
        if (params.dataIndex !== 0) return;
        var p0 = api.coord([0, 0]);
        var p1 = api.coord([1, 0]);
        var p2 = api.coord([0.5, h]);
        return {
          type: 'group',
          children: [
            { type: 'polygon', shape: { points: [p0, p1, p2] }, style: { fill: 'none', stroke: '#aaa', lineWidth: 2 } },
            { type: 'text', x: p0[0] - 10, y: p0[1] + 15, style: { text: 'A (100%)', fill: '#333', font: '12px sans-serif' } },
            { type: 'text', x: p1[0] - 10, y: p1[1] + 15, style: { text: 'B (100%)', fill: '#333', font: '12px sans-serif' } },
            { type: 'text', x: p2[0] - 15, y: p2[1] - 10, style: { text: 'C (100%)', fill: '#333', font: '12px sans-serif' } }
          ]
        };
      },
      data: [0],
      silent: true
    },
    {
      type: 'scatter',
      symbolSize: 14,
      data: transformedData,
      itemStyle: { color: '#5470c6', borderColor: '#fff', borderWidth: 1 },
      label: { show: true, formatter: function(p) { return p.data.name; }, position: 'top', fontSize: 10 }
    }
  ]
};
